import React from "react";
import styled from "styled-components";
import { Link } from "react-router-dom";

/**
 * Card component that displays a project or content card with image, title, and description
 * Styled to match Meta.com's modern card design with hover effects and rounded corners
 */
const Card = ({ title, description, image, imageAlt, link }) => {
  return (
    <CardContainer to={link}>
      <CardImage>
        <img src={image} alt={imageAlt} />
      </CardImage>
      <CardContent>
        <CardTitle>{title}</CardTitle>
        <CardDescription>{description}</CardDescription>
        <CardLink>
          Learn more
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
            <path 
              d="M17.5 12L6.5 12" 
              stroke="currentColor" 
              strokeWidth="1.5" 
              strokeLinecap="round" 
              strokeLinejoin="round"
            />
            <path 
              d="M12.5 7L17.5 12L12.5 17" 
              stroke="currentColor" 
              strokeWidth="1.5" 
              strokeLinecap="round" 
              strokeLinejoin="round"
            />
          </svg>
        </CardLink>
      </CardContent>
    </CardContainer>
  );
};

// Styled components with 2 space indentation as per coding standards
const CardContainer = styled(Link)`
  display: flex;
  flex-direction: column;
  background-color: white;
  border-radius: 12px;
  overflow: hidden;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  height: 100%;
  text-decoration: none;
  color: inherit;

  &:hover {
    transform: translateY(-8px);
    box-shadow: 0 12px 30px rgba(0, 0, 0, 0.1);

    img {
      transform: scale(1.05);
    }

    svg {
      transform: translateX(4px);
    }
  }
`;

const CardImage = styled.div`
  width: 100%;
  height: 220px;
  overflow: hidden;

  img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.5s ease;
  }
`;

const CardContent = styled.div`
  padding: 24px;
  display: flex;
  flex-direction: column;
  flex-grow: 1;
`;

const CardTitle = styled.h3`
  font-size: 20px;
  margin-bottom: 12px;
  color: var(--text-primary);
  font-weight: 600;
`;

const CardDescription = styled.p`
  font-size: 16px;
  line-height: 1.6;
  color: var(--text-secondary);
  margin-bottom: 24px;
  flex-grow: 1;
`;

const CardLink = styled.span`
  color: var(--primary-color);
  font-weight: 500;
  font-size: 16px;
  display: flex;
  align-items: center;
  margin-top: auto;

  svg {
    margin-left: 8px;
    transition: transform 0.2s ease;
  }
`;

export default Card;
